class Solution {
    int m, n, total, avail;
    unordered_map<int,int> mp;
public:
    Solution(int m, int n): m(m), n(n), total(m*n), avail(total) {}
    vector<int> flip() {
        int r = rand() % avail;
        int idx = mp.count(r) ? mp[r] : r;
        mp[r] = mp.count(avail-1) ? mp[avail-1] : avail-1;
        avail--;
        return {idx / n, idx % n};
    }
    void reset() { avail = total; mp.clear(); }
};
